try:
    lacima_gold_dimriskfactorid_flag = df_feature_flags.where("FlagName = 'lacima_gold_dimriskfactorid'").collect()[0]["FlagState"]
    lacima_gold_valueupdates_flag = df_feature_flags.where("FlagName = 'lacima_gold_valueupdates'").collect()[0]["FlagState"]
except Exception as e:
    print(e)

# Drop table and storage folder if exists
from py4j.protocol import Py4JJavaError

spark.sql(f"""DROP TABLE IF EXISTS {db_notebookname}.{db_tablename}""")

try:
    raw_output_path = f"abfss://{destination_container}@{destination_storage}.dfs.core.windows.net/{destination_path}/{db_tablename}"
    mssparkutils.fs.rm(raw_output_path,recurse=True)

    print("Delete successful")

except Py4JJavaError as error :
    if 'org.apache.hadoop.fs.PathNotFoundException' in str (error.java_exception):
        print("No such file or directory")

if lacima_gold_valueupdates_flag:
    # Create new dataframe that is a filter of df_gold  to labels "GENERIC-SOLAR-1_ELEC_SALES_UDC_pm_version Cost" and "GENERIC-SOLAR-1_ELEC_SALES_UDC_pm_version Revenue"
    Filtered_df_Gold = df_Gold[df_Gold['raSimulationSetOutputLabelId'].isin([22375, 22900, 21675, 22200, 21325, 21500, 22025, 22550, 21850, 22725, 22201, 22901, 22551, 22026, 21326, 22376, 22726, 21851, 21676, 21501])]
else:
    print("Feature not yet available")

if lacima_gold_valueupdates_flag:
    display(Filtered_df_Gold)
else:
    print("Feature not yet available")

if lacima_gold_valueupdates_flag:
    display(Joined_df.filter(col("Sum_Value_cost_PE").isNotNull()))
else:
    print("Feature not yet available")

if lacima_gold_valueupdates_flag:
    #Create new column to consolidate Value_d and new Value from joined dataframe - if Label = "GENERIC-SOLAR-1_ELEC_SALES_UDC_pm_version Profit/Earnings" then use Sum_Value_d_PE else use Value_d
    df_Gold = Joined_df.withColumn(
        "Value_d",
        fn.when(
            fn.col("raSimulationSetOutputLabelId").isin([22549, 22724, 22374, 21324, 21674, 21849, 21499, 22899, 22024, 22199]),
            fn.col("Sum_Value_cost_PE")
        ).otherwise(fn.col("Value_cost"))
    )
else:
    print("Feature not yet available")

if lacima_gold_valueupdates_flag:
    #Identify rows with Value != Null
    display(
        df_Gold
            .filter(col('raSimulationSetOutputLabelId').isin(
                22549, 22724, 22374, 21324, 21674, 21849, 21499, 22899,
                22024, 22199, 22375, 22900, 21675, 22200, 21325, 21500,
                22025, 22550, 21850, 22725
            ))
            .filter(col("Value_d").isNotNull())
    )
else:
    print("Feature not yet available")

if lacima_gold_valueupdates_flag:
    display(df_Gold)
else:
    print("Feature not yet available")
